import{_ as s,o as a,c as r,ai as n}from"./chunks/framework.LYGRWSbL.js";const b=JSON.parse('{"title":"Les verbes séparables","description":"","frontmatter":{},"headers":[],"relativePath":"module-3-quotidien/verbes-separables.md","filePath":"module-3-quotidien/verbes-separables.md","lastUpdated":1773298982000}'),i={name:"module-3-quotidien/verbes-separables.md"};function t(l,e,d,p,o,m){return a(),r("div",null,[...e[0]||(e[0]=[n('<h1 id="les-verbes-separables" tabindex="-1">Les verbes séparables <a class="header-anchor" href="#les-verbes-separables" aria-label="Permalink to “Les verbes séparables”">​</a></h1><p><strong>Prérequis :</strong> <a href="./articles-selon-les-cas.html">Articles selon les cas</a></p><p><strong>Objectif :</strong> comprendre comment fonctionnent les verbes séparables et savoir les utiliser au présent.</p><p>Les verbes séparables (<em>trennbare Verben</em>) sont des verbes composes d&#39;un préfixe et d&#39;un verbe de base. Au présent, le préfixe se detache et se place en fin de phrase. C&#39;est une des particularités les plus surprenantes de l&#39;allemand pour un francophone.</p><h2 id="le-principe" tabindex="-1">Le principe <a class="header-anchor" href="#le-principe" aria-label="Permalink to “Le principe”">​</a></h2><p>Prends <em>anrufen</em> (appeler au telephone) : il est compose du préfixe <em>an-</em> et du verbe <em>rufen</em> (crier, appeler).</p><p>Au présent, <em>anrufen</em> se conjugue normalement sur <em>rufen</em>, mais le préfixe <em>an</em> part en fin de phrase :</p><ul><li><em>Ich rufe dich <strong>an</strong>.</em> - Je t&#39;appelle.</li><li><em>Er ruft seine Mutter <strong>an</strong>.</em> - Il appelle sa mere.</li></ul><div class="warning custom-block"><p class="custom-block-title">Le préfixe va toujours en fin de phrase</p><p>C&#39;est la règle V2 du module 2 qui s&#39;applique : le verbe conjugue reste en position 2, et le préfixe detache se place en toute derniere position, après tous les autres éléments.</p><p><em>Ich rufe <strong>morgen</strong> dich <strong>an</strong>.</em> - Je t&#39;appelle <strong>demain</strong>.</p></div><h2 id="prefixes-separables-courants" tabindex="-1">Prefixes séparables courants <a class="header-anchor" href="#prefixes-separables-courants" aria-label="Permalink to “Prefixes séparables courants”">​</a></h2><div class="mt-4 grid grid-cols-2 gap-3"><div class="p-4 rounded-xl border border-gray-200"><div class="font-semibold text-green-700 mb-2">an-</div><div class="text-sm text-gray-600"><div class="flex justify-between py-1 border-b border-gray-100"><span class="font-medium">anrufen</span><span>appeler (tel.)</span></div><div class="flex justify-between py-1 border-b border-gray-100"><span class="font-medium">ankommen</span><span>arriver</span></div><div class="flex justify-between py-1"><span class="font-medium">anfangen</span><span>commencer</span></div></div></div><div class="p-4 rounded-xl border border-gray-200"><div class="font-semibold text-green-700 mb-2">auf-</div><div class="text-sm text-gray-600"><div class="flex justify-between py-1 border-b border-gray-100"><span class="font-medium">aufmachen</span><span>ouvrir</span></div><div class="flex justify-between py-1 border-b border-gray-100"><span class="font-medium">aufstehen</span><span>se lever</span></div><div class="flex justify-between py-1"><span class="font-medium">aufhoren</span><span>arreter de</span></div></div></div><div class="p-4 rounded-xl border border-gray-200"><div class="font-semibold text-green-700 mb-2">ab-</div><div class="text-sm text-gray-600"><div class="flex justify-between py-1 border-b border-gray-100"><span class="font-medium">abfahren</span><span>partir (vehicle)</span></div><div class="flex justify-between py-1 border-b border-gray-100"><span class="font-medium">abholen</span><span>aller chercher</span></div><div class="flex justify-between py-1"><span class="font-medium">abgeben</span><span>remettre</span></div></div></div><div class="p-4 rounded-xl border border-gray-200"><div class="font-semibold text-green-700 mb-2">mit-</div><div class="text-sm text-gray-600"><div class="flex justify-between py-1 border-b border-gray-100"><span class="font-medium">mitkommen</span><span>venir avec</span></div><div class="flex justify-between py-1 border-b border-gray-100"><span class="font-medium">mitnehmen</span><span>emmener / prendre</span></div><div class="flex justify-between py-1"><span class="font-medium">mitmachen</span><span>participer</span></div></div></div><div class="p-4 rounded-xl border border-gray-200"><div class="font-semibold text-green-700 mb-2">ein-</div><div class="text-sm text-gray-600"><div class="flex justify-between py-1 border-b border-gray-100"><span class="font-medium">einladen</span><span>inviter</span></div><div class="flex justify-between py-1 border-b border-gray-100"><span class="font-medium">einkaufen</span><span>faire les courses</span></div><div class="flex justify-between py-1"><span class="font-medium">einschlafen</span><span>s&#39;endormir</span></div></div></div><div class="p-4 rounded-xl border border-gray-200"><div class="font-semibold text-green-700 mb-2">zurück-</div><div class="text-sm text-gray-600"><div class="flex justify-between py-1 border-b border-gray-100"><span class="font-medium">zurückkommen</span><span>revenir</span></div><div class="flex justify-between py-1 border-b border-gray-100"><span class="font-medium">zurückgeben</span><span>rendre</span></div><div class="flex justify-between py-1"><span class="font-medium">zurückfahren</span><span>repartir</span></div></div></div></div><h2 id="exemples-en-phrases" tabindex="-1">Exemples en phrases <a class="header-anchor" href="#exemples-en-phrases" aria-label="Permalink to “Exemples en phrases”">​</a></h2><ul><li><em>Der Zug <strong>fahrt</strong> um 8 Uhr <strong>ab</strong>.</em> - Le train <strong>part</strong> a 8h.</li><li><em>Wann <strong>fangt</strong> der Film <strong>an</strong> ?</em> - Quand est-ce que le film <strong>commence</strong> ?</li><li><em>Ich <strong>stehe</strong> morgens um 7 <strong>auf</strong>.</em> - Je <strong>me leve</strong> a 7h le matin.</li><li><em>Komm<strong>st</strong> du mit ?</em> - Tu <strong>viens</strong> avec nous ?</li></ul><h2 id="reconnaitre-un-verbe-separable-dans-le-dictionnaire" tabindex="-1">Reconnaitre un verbe séparable dans le dictionnaire <a class="header-anchor" href="#reconnaitre-un-verbe-separable-dans-le-dictionnaire" aria-label="Permalink to “Reconnaitre un verbe séparable dans le dictionnaire”">​</a></h2><p>Dans un dictionnaire ou glossaire, les verbes séparables sont notés avec un tiret ou une barre verticale entre le préfixe et le verbe : <em>an|rufen</em>, <em>auf|stehen</em>, <em>ein|kaufen</em>. C&#39;est l&#39;indice que ce verbe se sépare à la conjugaison.</p><div class="info custom-block"><p class="custom-block-title">Les verbes non séparables existent aussi</p><p>Certains préfixes ne se séparent jamais : <em>be-</em>, <em>ge-</em>, <em>er-</em>, <em>ver-</em>, <em>zer-</em>, <em>ent-</em>, <em>emp-</em>, <em>miss-</em>. <em>Verstehen</em> (comprendre) ne se sépare pas : <em>Ich verstehe.</em> et non <em>Ich stehe ver.</em> Le dictionnaire indique toujours si le préfixe est séparable ou non.</p></div>',16)])])}const u=s(i,[["render",t]]);export{b as __pageData,u as default};
